// SPDX-License-Identifier: Apache-2.0 WITH LLVM-exception

// A example of static library loading in IREE. See the README.md for more info.
// Note: this demo requires artifacts from iree-compile before it will run.

#include <float.h>
#include <math.h>
#include "iree/base/alignment.h"
#include "iree/base/config.h"
#include "iree/hal/local/loaders/static_library_loader.h"
#include "iree/hal/drivers/local_sync/sync_device.h"
#include "iree/modules/hal/module.h"
#include "iree/runtime/api.h"
#include "iree/vm/api.h"
#include <stddef.h>
#include "host-c.h"
#include <stdint.h>
#include <time.h>

#ifdef PF_COUNTER
#include "nds32_pfcounter.h"
#endif

#ifdef __cplusplus
extern "C" {
#endif  //  __cplusplus
iree_status_t module_create(iree_vm_instance_t* v1, iree_allocator_t v2,
                               iree_vm_module_t** v3);
#ifdef __cplusplus
}  // extern "C"
#endif  //  __cplusplus

extern const iree_hal_executable_library_header_t**
QUERY(
    iree_hal_executable_library_version_t max_version,
    const iree_hal_executable_environment_v0_t* environment);


iree_status_t create_module(iree_vm_instance_t* instance, iree_vm_module_t** module) {
  return module_create(instance, iree_vm_instance_allocator(instance), module);
}

void print_success() { printf("static_library_run_c passed\n"); }
// A function to create the HAL device from the different backend targets.
// The HAL device is returned based on the implementation, and it must be
// released by the caller.
iree_status_t create_device_with_static_loader(iree_allocator_t host_allocator,
                                               iree_hal_device_t** out_device) {
  // Set paramters for the device created in the next step.
  iree_hal_sync_device_params_t params;
  iree_hal_sync_device_params_initialize(&params);

  // Register the statically linked executable library.
  const iree_hal_executable_library_query_fn_t libraries[] = {
      QUERY,
  };
  iree_hal_executable_loader_t* library_loader = NULL;
  iree_status_t status = iree_hal_static_library_loader_create(
      IREE_ARRAYSIZE(libraries), libraries,
      iree_hal_executable_import_provider_null(), host_allocator,
      &library_loader);

  // Use the default host allocator for buffer allocations.
  iree_string_view_t identifier = iree_make_cstring_view("local-sync");
  iree_hal_allocator_t* device_allocator = NULL;
  if (iree_status_is_ok(status)) {
    status = iree_hal_allocator_create_heap(identifier, host_allocator,
                                            host_allocator, &device_allocator);
  }

  // Create the device and release the executor and loader afterwards.
  if (iree_status_is_ok(status)) {
    status = iree_hal_sync_device_create(
        identifier, &params, /*loader_count=*/1, &library_loader,
        device_allocator, host_allocator, out_device);
  }

  iree_hal_allocator_release(device_allocator);
  iree_hal_executable_loader_release(library_loader);
  return status;
}

iree_status_t Run() {
  iree_status_t status = iree_ok_status();

  iree_runtime_instance_options_t instance_options;
  iree_runtime_instance_options_initialize(&instance_options);
  iree_runtime_instance_options_use_all_available_drivers(&instance_options);
  iree_runtime_instance_t* instance = NULL;

  IREE_RETURN_IF_ERROR(
    iree_runtime_instance_create(&instance_options,
                                          iree_allocator_system(), &instance), " instance create");

  // Create dylib device with static loader.
  iree_hal_device_t* device = NULL;
  IREE_RETURN_IF_ERROR(
    create_device_with_static_loader(iree_allocator_system(), &device), "create device");

  // Session configuration (one per loaded module to hold module state).
  iree_runtime_session_options_t session_options;
  iree_runtime_session_options_initialize(&session_options);
  iree_runtime_session_t* session = NULL;
  if (iree_status_is_ok(status)) {
    status = iree_runtime_session_create_with_device(
        instance, &session_options, device,
        iree_runtime_instance_host_allocator(instance), &session);
  }


  // Load bytecode module from the embedded data. Append to the session.
  iree_vm_module_t* module = NULL;

  IREE_RETURN_IF_ERROR(
    create_module(iree_runtime_instance_vm_instance(instance), &module), "create module");

  IREE_RETURN_IF_ERROR(
    iree_runtime_session_append_module(session, module),
    "session append module");

  // Lookup the entry point function call.
  const char kMainFunctionName[] = _FUNC;
  iree_runtime_call_t call;
  memset(&call, 0, sizeof(call));
  IREE_RETURN_IF_ERROR(
    iree_runtime_call_initialize_by_name(
        session, iree_make_cstring_view(kMainFunctionName), &call),
    "init call");

  iree_vm_list_t* inputs;
  IREE_CHECK_OK(iree_vm_list_create(iree_vm_make_value_type_def(IREE_VM_VALUE_TYPE_I32), 1,
                                    iree_allocator_system(), &inputs));
  iree_vm_value_t arg_value = iree_vm_value_make_i32(1);
  IREE_RETURN_IF_ERROR(iree_vm_list_push_value(inputs, &arg_value));

  iree_vm_list_t* outputs = NULL;
  IREE_CHECK_OK(iree_vm_list_create(iree_vm_make_value_type_def(IREE_VM_VALUE_TYPE_I32), 1,
                                    iree_allocator_system(), &outputs));

  printf("tune...ok\n");
//  clock_t start, end;
//  start = clock();
#ifdef PF_COUNTER
    startPFM;
#endif
  IREE_CHECK_OK(
      iree_runtime_session_call_by_name(session, iree_make_cstring_view(kMainFunctionName), inputs, outputs));
#ifdef PF_COUNTER
    stopPFM;
    readResult();
#endif
//  end = clock();
//  double diff = end - start; // ms
  printf(" PASS1 \n");
//  printf("seconds : %f  PASS2 \n", diff / CLOCKS_PER_SEC );
  iree_runtime_call_deinitialize(&call);

  // Cleanup session and instance.
  iree_hal_device_release(device);
  iree_runtime_session_release(session);
  iree_runtime_instance_release(instance);
  iree_vm_module_release(module);

  return status;
}

int main(int argc, char** argv) {
  __asm__ __volatile__ ( " csrs mstatus,  %0" :: "r"((unsigned long) 1 << 9) );

  iree_status_t result = Run();
  if (!iree_status_is_ok(result)) {
    iree_status_fprint(stderr, result);
    iree_status_ignore(result);
    return -1;
  }
  iree_status_ignore(result);
  return 0;
}

