static inline uint32_t verify_buffer(void *outBuf, void *goldenBuf, uint32_t length, uint32_t eByte)
{
    uint32_t i, maxDiff=0;

    if(eByte == 1)
    {
        int8_t *outPtr = (int8_t *)outBuf;
        int8_t *goldenPtr= (int8_t*)goldenBuf;

        for(i=0; i<length; i++)
        {
            uint32_t diff = abs(goldenPtr[i] - outPtr[i]);
            maxDiff = (diff > maxDiff) ? diff : maxDiff;

            // if(diff != 0)
            // {
            //     printf("out[%d] = %02x, golden[%d] = %02x\n", i, outPtr[i], i, goldenPtr[i]);
            // }
        }
    }
    else if(eByte == 2)
    {
        int16_t *outPtr = (int16_t*)outBuf;
        int16_t *goldenPtr= (int16_t*)goldenBuf;

        for(i=0; i<length; i++)
        {
            uint32_t diff = abs(goldenPtr[i] - outPtr[i]);
            maxDiff = (diff > maxDiff) ? diff : maxDiff;

            // if(diff != 0)
            // {
            //     printf("out[%d] = %02x, golden[%d] = %02x\n", i, outPtr[i], i, goldenPtr[i]);
            // }
        }
    }

    return maxDiff;
}

